# Snowflake-like ID generator
import time, threading

class Snowflake:
    EPOCH = 1700000000000
    def __init__(self, worker_id, dc_id=0):
        self.worker_id = worker_id
        self.dc_id = dc_id
        self.seq = 0
        self.last_ts = 0
        self.lock = threading.Lock()

    def generate(self):
        with self.lock:
            ts = int(time.time() * 1000) - self.EPOCH
            if ts < self.last_ts:
                raise RuntimeError("Clock moved backwards")
            if ts == self.last_ts:
                self.seq = (self.seq + 1) & 0xFFF
                if self.seq == 0:  # sequence exhausted, wait next ms
                    while ts <= self.last_ts:
                        ts = int(time.time() * 1000) - self.EPOCH
            else:
                self.seq = 0
            self.last_ts = ts
            return (ts << 22) | (self.dc_id << 17) | (self.worker_id << 12) | self.seq

    def encode(self, n):
        chars = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ"
        result = []
        while n > 0:
            result.append(chars[n % 62])
            n //= 62
        return "".join(reversed(result))

# URL Shortener service stub
class URLShortener:
    def __init__(self, id_gen, db, cache):
        self._gen = id_gen; self._db = db; self._cache = cache

    def shorten(self, long_url, user=None):
        nid = self._gen.generate()
        code = self._gen.encode(nid)
        self._db.write(code, long_url, user)
        self._cache.set(code, long_url, ttl=86400)
        return f"https://s.co/{code}"

    def resolve(self, code):
        url = self._cache.get(code)
        if url: return url
        url = self._db.read(code)
        if url: self._cache.set(code, url, ttl=3600)
        return url

# Adaptive bitrate manifest generation (HLS)
import os

class HLSPlaylist:
    def __init__(self, video_id, chunk_duration=10):
        self.video_id = video_id; self.chunk_dur = chunk_duration
        self.variants = []

    def add_variant(self, resolution, bitrate, codec):
        self.variants.append({
            "resolution": resolution, "bitrate": bitrate,
            "codec": codec, "playlist": f"{video_id}_{resolution}.m3u8"})

    def master_playlist(self):
        lines = ["#EXTM3U", "#EXT-X-VERSION:6"]
        for v in self.variants:
            lines.append(f'#EXT-X-STREAM-INF:BANDWIDTH={v["bitrate"]},'
                         f'RESOLUTION={v["resolution"]},CODECS="{v["codec"]}"')
            lines.append(v["playlist"])
        return "\n".join(lines)

    def variant_playlist(self, resolution, total_chunks):
        r = v["resolution"] if isinstance(resolution, str) else resolution
        v = next(v for v in self.variants if v["resolution"] == r)
        lines = ["#EXTM3U", "#EXT-X-TARGETDURATION:" + str(self.chunk_dur),
                 "#EXT-X-VERSION:6", "#EXT-X-PLAYLIST-TYPE:VOD"]
        for i in range(total_chunks):
            lines.append(f"#EXTINF:{self.chunk_dur:.1f},")
            lines.append(f"{self.video_id}_{r}_{i:05d}.ts")
        lines.append("#EXT-X-ENDLIST")
        return "\n".join(lines)

