# Hybrid fanout strategy
import heapq

class TimelineService:
    def __init__(self, timeline_cache, tweet_cache, fanout_worker):
        self._tl = timeline_cache
        self._tc = tweet_cache
        self._fanout = fanout_worker
        self.CELEB_THRESH = 30000

    def post_tweet(self, user_id, tweet_id, follower_ids):
        if len(follower_ids) <= self.CELEB_THRESH:
            self._fanout.push_batch(tweet_id, follower_ids)
        else:
            self._fanout.append_celeb_timeline(user_id, tweet_id)

    def get_timeline(self, user_id, count=200):
        tweets = self._tl.zrevrange(f"tl:{user_id}", 0, count-1)
        result = {}
        for tid in tweets:
            t = self._tc.get(f"tweet:{tid}")
            if t: result[tid] = t
        # Merge celeb tweets for followed celebrities
        celeb_ids = self._fanout.followed_celebs(user_id)
        for cid in celeb_ids:
            celeb_tweets = self._tl.zrevrange(f"celeb:{cid}", 0, 50)
            for tid in celeb_tweets:
                if tid not in result:
                    t = self._tc.get(f"tweet:{tid}")
                    if t: result[tid] = t
        # Sort by timestamp and trim
        sorted_ids = sorted(result.keys(), key=lambda x: result[x]["ts"], reverse=True)[:count]
        return [result[i] for i in sorted_ids]

# Ranked timeline (ML-based)
class TimelineRanker:
    def rank(self, tweets, user_profile):
        scored = []
        for t in tweets:
            score = 0
            score += 0.3 * t.get("likes", 0) / max(t.get("impressions", 1), 1)
            score += 0.2 * (1 if user_profile.get("id") == t.get("author_id") else 0)
            score += 0.2 * (1 if t.get("media_type") else 0)
            score += 0.1 * (1 / (1 + t.get("age_hours", 24)))
            scored.append((score, t))
        return [t for _, t in sorted(scored, reverse=True)]

# Geo-index with S2-like cells (simplified quad-tree)
class QuadTree:
    def __init__(self, lat, lng, radius_km, capacity=10):
        self.bounds = (lat-radius_km/111, lat+radius_km/111,
                       lng-radius_km/111, lng+radius_km/111)  # deg
        self.capacity = capacity
        self.drivers = []
        self.children = None

    def _contains(self, lat, lng):
        return (self.bounds[0] <= lat <= self.bounds[1] and
                self.bounds[2] <= lng <= self.bounds[3])

    def insert(self, driver):
        if not self._contains(driver["lat"], driver["lng"]):
            return False
        if len(self.drivers) < self.capacity:
            self.drivers.append(driver)
            return True
        if not self.children:
            self._split()
        for c in self.children:
            if c.insert(driver): return True
        return True

    def _split(self):
        lat_mid = (self.bounds[0]+self.bounds[1])/2
        lng_mid = (self.bounds[2]+self.bounds[3])/2
        self.children = [
            QuadTree(lat_mid, lng_mid, 0, self.capacity),
            QuadTree(lat_mid, lng_mid, 0, self.capacity),
            QuadTree(lat_mid, lng_mid, 0, self.capacity),
            QuadTree(lat_mid, lng_mid, 0, self.capacity),
        ]

    def query(self, lat, lng, radius_km):
        found = []
        if not self._contains(lat, lng): return found
        for d in self.drivers:
            dist = ((d["lat"]-lat)**2+(d["lng"]-lng)**2)**0.5*111
            if dist <= radius_km: found.append(d)
        if self.children:
            for c in self.children: found.extend(c.query(lat, lng, radius_km))
        return found

# Dispatch
class Dispatcher:
    def __init__(self, geo_index):
        self._geo = geo_index

    def find_driver(self, rider_lat, rider_lng, radius_km=2):
        drivers = self._geo.query(rider_lat, rider_lng, radius_km)
        if not drivers:
            drivers = self._geo.query(rider_lat, rider_lng, radius_km*3)
        return min(drivers, key=lambda d: d.get("eta", 999)) if drivers else None

# Block-level dedup for file sync
import hashlib

class BlockStore:
    def __init__(self):
        self._blocks = {}  # hash -> bytes
        self._refs = {}    # hash -> ref_count

    def store(self, data):
        h = hashlib.sha256(data).hexdigest()
        if h not in self._blocks:
            self._blocks[h] = data
            self._refs[h] = 0
        self._refs[h] += 1
        return h

    def release(self, h):
        if h in self._refs:
            self._refs[h] -= 1
            if self._refs[h] <= 0:
                del self._blocks[h]
                del self._refs[h]

    def read(self, h):
        return self._blocks.get(h)

class FileSync:
    def __init__(self, store, block_size=4*1024*1024):
        self._store = store; self._bs = block_size

    def _chunks(self, data):
        return [data[i:i+self._bs] for i in range(0, len(data), self._bs)]

    def upload_file(self, file_id, data):
        chunks = self._chunks(data)
        block_ids = [self._store.store(c) for c in chunks]
        return {"file_id": file_id, "blocks": block_ids,
                "size": len(data), "block_hashes": block_ids}

    def download_file(self, manifest):
        chunks = [self._store.read(h) for h in manifest["blocks"]]
        return b"".join(c for c in chunks if c)

    def delta_upload(self, file_id, old_manifest, new_data):
        new_chunks = self._chunks(new_data)
        new_blocks = []
        for chunk in new_chunks:
            h = hashlib.sha256(chunk).hexdigest()
            if h not in old_manifest.get("block_hashes", []):
                self._store.store(chunk)
            new_blocks.append(h)
        return {"file_id": file_id, "blocks": new_blocks}

# Dynamo-style KV store with consistent hashing
import hashlib

class DynamoNode:
    def __init__(self, nid):
        self.id = nid; self.data = {}; self.vclocks = {}

    def put(self, key, val, vclock):
        self.data[key] = val
        self.vclocks[key] = vclock

    def get(self, key):
        return (self.data.get(key), self.vclocks.get(key))

class DynamoRing:
    def __init__(self, nodes, N=3, W=2, R=2):
        self.ring = {hashlib.md5(n.id.encode()).hexdigest(): n for n in nodes}
        self.N= N; self.W = W; self.R = R
        self.sorted_keys = sorted(self.ring)

    def _pref_list(self, key):
        h = hashlib.md5(key.encode()).hexdigest()
        idx = next(i for i,k in enumerate(self.sorted_keys) if k >= h)
        return [self.ring[self.sorted_keys[(idx+i)%len(self.sorted_keys)]]
                for i in range(self.N)]

    def put(self, key, val):
        nodes = self._pref_list(key)
        vclock = {}
        success = 0
        for n in nodes:
            existing, vc = n.get(key)
            vclock = vc or vclock
            vclock[n.id] = vclock.get(n.id, 0) + 1
        for n in nodes:
            try:
                n.put(key, val, vclock)
                success += 1
            except: pass
        return success >= self.W

    def get(self, key):
        nodes = self._pref_list(key)
        vals = []
        for n in nodes:
            try:
                v, vc = n.get(key)
                if v is not None: vals.append((v, vc))
            except: pass
        if len(vals) < self.R: return None
        latest = max(vals, key=lambda x: sum(x[1].values()))
        return latest[0]

# Merkle tree for anti-entropy
class MerkleTree:
    def __init__(self, data):
        self.tree = {}
        self._build(data)

    def _hash(self, v):
        return hashlib.sha256(str(v).encode()).hexdigest()[:8]

    def _build(self, data):
        leaves = sorted(data.items())
        level = [self._hash(k+v) for k,v in leaves]
        self.tree[0] = level
        i = 0
        while len(level) > 1:
            i += 1
            level = [self._hash(level[j]+level[j+1]) if j+1<len(level) else level[j]
                     for j in range(0, len(level), 2)]
            self.tree[i] = level

    def root(self):
        return self.tree[max(self.tree)][0]

# In-memory log with offset management
import os, time, threading

class LogSegment:
    def __init__(self, path, max_bytes=1024*1024*1024):
        self.path = path; self.max_bytes = max_bytes
        self.msgs = []  # [(offset, timestamp, key, value), ...]
        self.base_offset = 0

    def append(self, msg):
        self.msgs.append(msg)
        return len(self.msgs) - 1

    def read(self, offset, max_bytes=None):
        idx = offset - self.base_offset
        if 0 <= idx < len(self.msgs):
            return self.msgs[idx]
        return None

    def is_full(self):
        return len(self.msgs) * 100 >= self.max_bytes

class Partition:
    def __init__(self, topic, pid, brokers):
        self.topic = topic; self.pid = pid
        self.leader = None; self.followers = []
        self.segments = [LogSegment(f"/data/{topic}/{pid}/00000000000000000000.log")]
        self.leader_epoch = 0

    def append(self, key, val):
        seg = self.segments[-1]
        offset = seg.base_offset + len(seg.msgs)
        msg = (offset, int(time.time()*1000), key, val)
        seg.append(msg)
        if seg.is_full():
            self._roll()
        return offset

    def _roll(self):
        new_base = self.segments[-1].base_offset + len(self.segments[-1].msgs)
        seg = LogSegment(f"/data/{self.topic}/{self.pid}/{new_base:020d}.log")
        seg.base_offset = new_base
        self.segments.append(seg)

    def read(self, offset):
        for seg in reversed(self.segments):
            if offset >= seg.base_offset:
                return seg.read(offset)
        return None

class ConsumerGroup:
    def __init__(self, group_id):
        self.group_id = group_id
        self.offsets = {}  # topic_partition -> offset

    def commit(self, topic, partition, offset):
        self.offsets[f"{topic}:{partition}"] = offset

    def next_offset(self, topic, partition):
        return self.offsets.get(f"{topic}:{partition}", 0)

# Partition assignment: range (default) vs sticky vs cooperative
class PartitionAssignor:
    @staticmethod
    def range_assign(consumers, partitions):
        per_consumer = len(partitions) // len(consumers)
        remainder = len(partitions) % len(consumers)
        result = {}
        start = 0
        for i, c in enumerate(sorted(consumers)):
            n = per_consumer + (1 if i < remainder else 0)
            result[c] = partitions[start:start+n]
            start += n
        return result

# Web crawler frontier with politeness
import time, heapq

class URLFrontier:
    def __init__(self):
        self.host_queues = {}  # host -> list of URLs
        self.last_fetch = {}   # host -> timestamp
        self.politeness_delay = 1.0

    def add_url(self, url):
        from urllib.parse import urlparse
        host = urlparse(url).netloc
        if host not in self.host_queues:
            self.host_queues[host] = []
        self.host_queues[host].append(url)

    def next_url(self):
        available = [(host, q) for host, q in self.host_queues.items()
                     if q and time.time() - self.last_fetch.get(host, 0) >= self.politeness_delay]
        if not available: return None
        host, q = available[0]  # round-robin
        url = q.pop(0)
        self.last_fetch[host] = time.time()
        return url

# Crawler worker
class CrawlerWorker:
    def __init__(self, frontier, parser, store):
        self._frontier = frontier; self._parser = parser
        self._store = store; self._fetched = set()

    def crawl(self, max_pages=1000):
        for _ in range(max_pages):
            url = self._frontier.next_url()
            if not url: break
            if url in self._fetched: continue
            try:
                status, content = self._fetch(url)
                if status == 200:
                    links = self._parser.extract_links(url, content)
                    for link in links:
                        self._frontier.add_url(link)
                    self._store.put(url, content)
                elif status in (429, 503):
                    self._frontier.last_fetch[urlparse(url).netloc] = time.time() + 60
            except:
                pass
            self._fetched.add(url)

    def _fetch(self, url):
        return 200, f"<html><body>content of {url}</body></html>"

# Simhash for near-duplicate detection
class SimHash:
    def __init__(self, bits=64):
        self.bits = bits

    def hash(self, tokens):
        v = [0] * self.bits
        for token in set(tokens):
            h = hash(token)
            for i in range(self.bits):
                if h & (1 << i):
                    v[i] += 1
                else:
                    v[i] -= 1
        return sum((1 << i) for i in range(self.bits) if v[i] > 0)

    def hamming(self, a, b):
        return bin(a ^ b).count("1")

# A* routing with heuristic
import heapq

class Graph:
    def __init__(self):
        self.nodes = {}  # id -> (lat, lng)
        self.edges = {}  # (u,v) -> cost
        self.adj = {}    # node -> [(neighbor, cost), ...]

    def add_edge(self, u, v, cost):
        self.adj.setdefault(u, []).append((v, cost))
        self.adj.setdefault(v, []).append((u, cost))
        self.edges[(u,v)] = self.edges[(v,u)] = cost

    def add_node(self, nid, lat, lng):
        self.nodes[nid] = (lat, lng)

    def heuristic(self, a, b):
        la1, lo1 = self.nodes.get(a, (0,0))
        la2, lo2 = self.nodes.get(b, (0,0))
        return ((la1-la2)**2 + (lo1-lo2)**2)**0.5 * 111000

    def astar(self, start, goal):
        frontier = [(0, start)]
        came_from = {}; cost_so_far = {start: 0}
        while frontier:
            _, current = heapq.heappop(frontier)
            if current == goal: break
            for nxt, cost in self.adj.get(current, []):
                new_cost = cost_so_far.get(current, 0) + cost
                if nxt not in cost_so_far or new_cost < cost_so_far[nxt]:
                    cost_so_far[nxt] = new_cost
                    priority = new_cost + self.heuristic(goal, nxt)
                    heapq.heappush(frontier, (priority, nxt))
                    came_from[nxt] = current
        path = []
        curr = goal
        while curr in came_from:
            path.append(curr)
            curr = came_from[curr]
        path.append(start)
        return list(reversed(path)), cost_so_far.get(goal, 0)

# S2 region cover for tile computation
class S2Region:
    @staticmethod
    def cell_id(lat, lng, level=15):
        """Simplified cell ID (production uses S2 library)."""
        return f"S2_{level}_{int(lat*100)}_{int(lng*100)}"

    @staticmethod
    def covering(lat, lng, radius_m, level=15):
        cells = set()
        for dlat in range(-10, 11):
            for dlng in range(-10, 11):
                clat = lat + dlat * radius_m / 111000
                clng = lng + dlng * radius_m / (111000 * abs(lat or 1))
                cells.add(S2Region.cell_id(clat, clng, level))
        return cells

# Inverted index with skip lists
import bisect

class InvertedIndex:
    def __init__(self):
        self.postings = {}  # term -> sorted list of doc_ids
        self.positions = {}  # (term, doc_id) -> positions in doc
        self.doc_count = 0

    def add_doc(self, doc_id, tokens):
        self.doc_count += 1
        for pos, token in enumerate(tokens):
            if token not in self.postings:
                self.postings[token] = []
                self.positions[token] = {}
            if not self.postings[token] or self.postings[token][-1] != doc_id:
                self.postings[token].append(doc_id)
            self.positions[token].setdefault(doc_id, []).append(pos)

    def search(self, term):
        return self.postings.get(term, [])

    def phrase_search(self, terms):
        if not terms: return []
        posting_lists = [self.postings.get(t, []) for t in terms]
        if any(not l for l in posting_lists): return []
        result = []
        for doc_id in posting_lists[0]:
            all_match = True
            for i, term in enumerate(terms[1:], 1):
                positions = self.positions[term].get(doc_id, [])
                prev_positions = self.positions[terms[i-1]].get(doc_id, [])
                if not any(p+1 in positions for p in prev_positions):
                    all_match = False
                    break
            if all_match: result.append(doc_id)
        return result

    def tf_idf(self, term, doc_id):
        postings = self.postings.get(term, [])
        df = len(postings)
        if df == 0: return 0
        tf = len(self.positions.get(term, {}).get(doc_id, []))
        idf = (self.doc_count / df)
        return tf * (1 + idf)

# BM25 scoring (Okapi BM25)
class BM25:
    def __init__(self, index, k1=1.5, b=0.75):
        self.index = index; self.k1 = k1; self.b = b
        self.avg_doc_len = 200  # average tokens per doc

    def score(self, query_terms, doc_id):
        score = 0
        doc_len = sum(len(pos.get(doc_id, []))
                      for pos in self.index.positions.values())
        for term in query_terms:
            postings = self.index.postings.get(term, [])
            df = len(postings)
            if df == 0: continue
            tf = len(self.index.positions.get(term, {}).get(doc_id, []))
            numerator = tf * (self.k1 + 1)
            denominator = tf + self.k1 * (1 - self.b + self.b * doc_len / self.avg_doc_len)
            score += numerator / denominator * (self.index.doc_count / df)
        return score
